+#[derive(Clone, Copy, Debug)]
+struct Baseline {
+    agent_count: usize,
+    avg_energy: f32,
+    avg_health: f32,
+}
+
+fn diff_i(value: i64) -> String {
+    if value > 0 {
+        format!("(+{value})")
+    } else if value < 0 {
+        format!("({value})")
+    } else {
+        String::from("(+0)")
+    }
+}
+
+fn diff_f(value: f32) -> String {
+    if value > 0.0 {
+        format!("(+{:.2})", value)
+    } else if value < 0.0 {
+        format!("({:.2})", value)
+    } else {
+        String::from("(+0.00)")
+    }
+}
+
